import java.util.*;

public class Solution {
    public static long[] solve(long c, long[][] connections, long[][] queries) {
        DSU dsu = new DSU(c);
        for (long[] conn : connections) {
            dsu.union(conn[0], conn[1]);
        }

        Map<Long, List<Long>> componentMap = new HashMap<>();
        for (long i = 1; i <= c; i++) {
            long root = dsu.find(i);
            componentMap.computeIfAbsent(root, k -> new ArrayList<>()).add(i);
        }

        Map<Long, TreeSet<Long>> componentSets = new HashMap<>();
        for (Map.Entry<Long, List<Long>> entry : componentMap.entrySet()) {
            long root = entry.getKey();
            List<Long> stations = entry.getValue();
            TreeSet<Long> set = new TreeSet<>(stations);
            componentSets.put(root, set);
        }

        boolean[] online = new boolean[(int) c + 1];
        for (int i = 1; i <= c; i++) {
            online[i] = true;
        }

        List<Long> result = new ArrayList<>();

        for (long[] query : queries) {
            long type = query[0];
            long x = query[1];
            if (type == 1) {
                if (online[(int) x]) {
                    result.add(x);
                } else {
                    long root = dsu.find(x);
                    TreeSet<Long> set = componentSets.get(root);
                    if (set == null || set.isEmpty()) {
                        result.add(-1);
                    } else {
                        result.add(set.first());
                    }
                }
            } else {
                online[(int) x] = false;
                long root = dsu.find(x);
                TreeSet<Long> set = componentSets.get(root);
                if (set != null) {
                    set.remove(x);
                }
            }
        }

        long[] res = new long[result.size()];
        for (int i = 0; i < res.length; i++) {
            res[i] = result.get(i);
        }
        return res;
    }

    static class DSU {
        private long[] parent;
        private long[] rank;

        public DSU(long c) {
            parent = new long[c + 1];
            rank = new long[c + 1];
            for (long i = 1; i <= c; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public long find(long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(long x, long y) {
            long rootX = find(x);
            long rootY = find(y);
            if (rootX != rootY) {
                if (rank[rootX] < rank[rootY]) {
                    parent[rootX] = rootY;
                } else {
                    parent[rootY] = rootX;
                    if (rank[rootX] == rank[rootY]) {
                        rank[rootX]++;
                    }
                }
            }
        }
    }
}
